+        OptionsClass: LinkStyleOptions, nameKey: 'rules.link-style.image-style.name', descriptionKey: 'rules.link-style.image-style.description', optionsKey: 'imageStyle',
+        records: linkStyleRecords,
+      }),
+    ];
+  }
+}
+
+const linkStyleRecords: {value: LinkStyleValue, description: string}[] = [
+  {value: 'no-change', description: 'Do not change this link type.'},
+  {value: 'markdown', description: 'Convert Obsidian wiki syntax to Markdown syntax.'},
+  {value: 'wiki', description: 'Convert Markdown syntax to Obsidian wiki syntax.'},
+];
+
+function convertWikiLinks(text: string, options: LinkStyleOptions): string {
+  return text.replace(/(!?)\\[\\[([^\\]\
]+)\\]\\]/g, (whole, imageMarker: string, contents: string) => {
+    const isImage = imageMarker === '!';
+    if ((isImage ? options.imageStyle : options.linkStyle) !== 'markdown') return whole;
+
+    const separator = contents.indexOf('|');
+    const target = separator === -1 ? contents : contents.substring(0, separator);
+    let display = separator === -1 ? defaultDisplay(target) : contents.substring(separator + 1);
+    if (isImage && /^(300|300x200)$/.test(display)) display = target;
+    return isImage ? `![${display}](${target})` : `[${display}](${target})`;
+  });
+}
+
+function convertMarkdownLinks(text: string, options: LinkStyleOptions): string {
+  let result = '';
+  for (let index = 0; index < text.length;) {
+    const parsed = parseMarkdownLink(text, index);
+    if (!parsed || (parsed.image ? options.imageStyle : options.linkStyle) !== 'wiki' || parsed.target.includes('://')) {
+      result += text[index++];
+      continue;
+    }
+    const display = unescapeMarkdown(parsed.label);
+    const target = unescapeMarkdown(parsed.target);
+    const omitDisplay = parsed.image ? display === '' || display === target : display === target || display === defaultDisplay(target);
+    result += `${parsed.image ? '!' : ''}[[${target}${omitDisplay ? '' : `|${display}`}]]`;
+    index = parsed.end;
+  }
+  return result;
+}
+
+type ParsedMarkdownLink = {image: boolean, label: string, target: string, end: number};
+
+function parseMarkdownLink(text: string, start: number): ParsedMarkdownLink | null {
+  const image = text[start] === '!';
+  const labelStart = start + (image ? 1 : 0);
+  if (text[labelStart] !== '[') return null;
+  const labelEnd = findClosingBracket(text, labelStart);
+  if (labelEnd === -1 || text[labelEnd + 1] !== '(') return null;
+  const close = findClosingParenthesis(text, labelEnd + 1);
+  if (close === -1) return null;
+  const label = text.substring(labelStart + 1, labelEnd);
+  const area = text.substring(labelEnd + 2, close);
+  if (label.includes('\
') || area.includes('\
')) return null;
+  const target = parseDestination(area);
+  return target === null ? null : {image, label, target, end: close + 1};
+}
+
+function findClosingBracket(text: string, open: number): number {
+  let depth = 0;
+  for (let i = open; i < text.length; i++) {
+    if (text[i] === '\\\') { i++; continue; }
+    if (text[i] === '[') depth++;
+    if (text[i] === ']' && --depth === 0) return i;
+    if (text[i] === '\
') return -1;
+  }
+  return -1;
+}
+
+function findClosingParenthesis(text: string, open: number): number {
+  let depth = 0;
+  for (let i = open; i < text.length; i++) {
+    if (text[i] === '\\\') { i++; continue; }
+    if (text[i] === '(') depth++;
+    if (text[i] === ')' && --depth === 0) return i;
+    if (text[i] === '\
') return -1;
+  }
+  return -1;
+}
+
+function parseDestination(area: string): string | null {
+  const trimmed = area.trim();
+  if (trimmed.startsWith('<')) {
+    const close = findUnescaped(trimmed, '>', 1);
+    return close !== -1 && trimmed.substring(close + 1).trim() === '' ? trimmed.substring(1, close) : null;
+  }
+  // Whitespace outside angle brackets denotes a Markdown title, which this rule leaves intact.
+  return hasUnescapedWhitespace(trimmed) ? null : trimmed;
+}
+
+function findUnescaped(text: string, character: string, start: number): number {
+  for (let i = start; i < text.length; i++) {
+    if (text[i] === '\\\') { i++; continue; }
+    if (text[i] === character) return i;
+  }
+  return -1;
+}
+
+function hasUnescapedWhitespace(text: string): boolean {
+  for (let i = 0; i < text.length; i++) {
+    if (text[i] === '\\\') { i++; continue; }
+    if (/\\s/.test(text[i])) return true;
+  }
+  return false;
+}
+
+function unescapeMarkdown(value: string): string {
+  return value.replace(/\\\\(.)/g, '$1');
+}
+
+function defaultDisplay(target: string): string {
+  const hash = target.indexOf('#');
+  if (hash === -1) return target;
+  const page = target.substring(0, hash);
+  const heading = target.substring(hash + 1);
+  return page ? `${page} > ${heading}` : heading;
